SELECT server_id, MAX(metric_value) AS max_metric_value
FROM server_performance_logs
GROUP BY server_id;

SELECT metric_value
FROM server_performance_logs
WHERE metric_value > 80;

SELECT AVG(metric_value) AS average_metric, unit
FROM server_performance_logs
WHERE server_id = 1;

SELECT AVG(metric_value) AS average_metric
FROM server_performance_logs
WHERE server_id = 1;

SELECT server_name, server_type
FROM servers
ORDER BY server_name;

SELECT server_id, metric_value, timestamp
FROM server_performance_logs
ORDER BY timestamp DESC;

SELECT MAX(metric_value) AS max_metric_value
FROM server_performance_logs
WHERE server_id = 1;
